using System;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class Event
{
    public int Id { get; set; }
    public string Name { get; set; }
    public int AvailableSeats { get; set; }
    public byte[] RowVersion { get; set; }
}

public class Booking
{
    public int Id { get; set; }
    public int EventId { get; set; }
    public int TicketCount { get; set; }
    public DateTime BookingDate { get; set; }
    public string CustomerEmail { get; set; }
}

public class EventBookingContext : DbContext
{
    public EventBookingContext(DbContextOptions<EventBookingContext> options) : base(options) { }

    public DbSet<Event> Events { get; set; }
    public DbSet<Booking> Bookings { get; set; }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Event>()
            .Property(e => e.RowVersion)
            .IsRowVersion();
    }
}

public class PurchaseResult
{
    public bool Success { get; set; }
    public string Message { get; set; }
    public int? BookingId { get; set; }
}

public class TicketBookingService
{
    private readonly EventBookingContext _context;
    private const int MaxRetries = 3;

    public TicketBookingService(EventBookingContext context)
    {
        _context = context;
    }

    public async Task<PurchaseResult> PurchaseTicketsAsync(int eventId, int quantity, string customerEmail)
    {
        if (quantity <= 0)
        {
            return new PurchaseResult
            {
                Success = false,
                Message = "Quantity must be greater than zero"
            };
        }

        if (string.IsNullOrWhiteSpace(customerEmail))
        {
            return new PurchaseResult
            {
                Success = false,
                Message = "Customer email is required"
            };
        }

        int retryCount = 0;

        while (retryCount < MaxRetries)
        {
            try
            {
                var eventEntity = await _context.Events
                    .FirstOrDefaultAsync(e => e.Id == eventId);

                if (eventEntity == null)
                {
                    return new PurchaseResult
                    {
                        Success = false,
                        Message = "Event not found"
                    };
                }

                if (eventEntity.AvailableSeats < quantity)
                {
                    return new PurchaseResult
                    {
                        Success = false,
                        Message = $"Insufficient seats available. Only {eventEntity.AvailableSeats} seats remaining"
                    };
                }

                eventEntity.AvailableSeats -= quantity;

                var booking = new Booking
                {
                    EventId = eventId,
                    TicketCount = quantity,
                    BookingDate = DateTime.UtcNow,
                    CustomerEmail = customerEmail
                };

                _context.Bookings.Add(booking);

                await _context.SaveChangesAsync();

                return new PurchaseResult
                {
                    Success = true,
                    Message = "Tickets purchased successfully",
                    BookingId = booking.Id
                };
            }
            catch (DbUpdateConcurrencyException)
            {
                retryCount++;

                foreach (var entry in _context.ChangeTracker.Entries())
                {
                    if (entry.Entity is Event)
                    {
                        await entry.ReloadAsync();
                    }
                    else if (entry.Entity is Booking)
                    {
                        entry.State = EntityState.Detached;
                    }
                }

                if (retryCount >= MaxRetries)
                {
                    return new PurchaseResult
                    {
                        Success = false,
                        Message = "Unable to complete purchase due to high demand. Please try again"
                    };
                }

                await Task.Delay(100 * retryCount);
            }
            catch (Exception ex)
            {
                return new PurchaseResult
                {
                    Success = false,
                    Message = $"Error processing purchase: {ex.Message}"
                };
            }
        }

        return new PurchaseResult
        {
            Success = false,
            Message = "Purchase failed after maximum retries"
        };
    }

    public async Task<PurchaseResult> PurchaseTicketsWithIsolationAsync(int eventId, int quantity, string customerEmail)
    {
        if (quantity <= 0)
        {
            return new PurchaseResult
            {
                Success = false,
                Message = "Quantity must be greater than zero"
            };
        }

        if (string.IsNullOrWhiteSpace(customerEmail))
        {
            return new PurchaseResult
            {
                Success = false,
                Message = "Customer email is required"
            };
        }

        using var transaction = await _context.Database.BeginTransactionAsync(
            System.Data.IsolationLevel.Serializable);

        try
        {
            var eventEntity = await _context.Events
                .FromSqlInterpolated($"SELECT * FROM Events WITH (UPDLOCK, ROWLOCK) WHERE Id = {eventId}")
                .FirstOrDefaultAsync();

            if (eventEntity == null)
            {
                await transaction.RollbackAsync();
                return new PurchaseResult
                {
                    Success = false,
                    Message = "Event not found"
                };
            }

            if (eventEntity.AvailableSeats < quantity)
            {
                await transaction.RollbackAsync();
                return new PurchaseResult
                {
                    Success = false,
                    Message = $"Insufficient seats available. Only {eventEntity.AvailableSeats} seats remaining"
                };
            }

            eventEntity.AvailableSeats -= quantity;

            var booking = new Booking
            {
                EventId = eventId,
                TicketCount = quantity,
                BookingDate = DateTime.UtcNow,
                CustomerEmail = customerEmail
            };

            _context.Bookings.Add(booking);

            await _context.SaveChangesAsync();
            await transaction.CommitAsync();

            return new PurchaseResult
            {
                Success = true,
                Message = "Tickets purchased successfully",
                BookingId = booking.Id
            };
        }
        catch (Exception ex)
        {
            await transaction.RollbackAsync();
            return new PurchaseResult
            {
                Success = false,
                Message = $"Error processing purchase: {ex.Message}"
            };
        }
    }
}